array_types.code:
type CSR_EWUP_Field_Array is array (1 .. 8) of Boolean with
   Component_Size => 1,
   Size           => 8;

record_types.code:
type CR_Register is record
   LPDS : Boolean := False;
   PDDS : Boolean := False;
   CWUF : Boolean := False;
   CSBF : Boolean := False;
   PVDE : Boolean := False;
   PLS : CR_PLS_Field := 16#0#;
   DBP : Boolean := False;
   Reserved_9_31 : HAL.UInt23 := 16#0#;
end record;

type CSR_EWUP_Field (As_Array : Boolean := False) is record
   case As_Array is
      when False =>
         Val : HAL.UInt8;
      when True =>
         Arr : CSR_EWUP_Field_Array;
   end case;
end record;

type CSR_Register is record
   WUF : Boolean := False;
   SBF : Boolean := False;
   PVDO : Boolean := False;
   VREFINTRDY : Boolean := False;
   Reserved_4_7 : HAL.UInt4 := 16#0#;
   EWUP : CSR_EWUP_Field := (As_Array => False, Val => 16#0#);
   Reserved_16_31 : HAL.UInt16 := 16#0#;
end record;

type PWR_Peripheral is record
   CR : aliased CR_Register;
   CSR : aliased CSR_Register;
end record;

variables.code:
PWR_Periph : aliased PWR_Peripheral with
   Import,
   Address => PWR_Base;
